import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  ListPackagesSchema,
  UpdatePackageSchema,
  RemovePackageSchema,
  InstallRecommendedSchema,
  ApiResult,
  InstalledPackage,
} from './types';
import { sshService } from '../services/SSHService';

export function registerPackagesHandlers() {
  ipcMain.handle(IPC_CHANNELS.PACKAGES_LIST, async (_event, input): Promise<ApiResult<InstalledPackage[]>> => {
    try {
      const { serverId } = ListPackagesSchema.parse(input);

      // Execute command to list all installed packages
      // Using apt list --installed which has better formatting
      const result = await sshService.executeCommand(
        serverId,
        'apt list --installed 2>/dev/null | tail -n +2' // Skip the "Listing..." header
      );

      if (!result.stdout) {
        return { success: true, data: [] };
      }

      const packages: InstalledPackage[] = [];
      const lines = result.stdout.trim().split('\n');

      for (const line of lines) {
        // Format: package/source,now version architecture [status]
        // Example: acl/noble-updates,now 2.3.2-1build1.1 amd64 [installed]

        // Match the pattern: package_name/... version architecture [...]
        const match = line.match(/^([^/]+)\/\S+\s+(\S+)\s+(\S+)\s+\[/);

        if (match) {
          const [, name, version, architecture] = match;
          packages.push({
            name,
            version,
            architecture,
          });
        }
      }

      return { success: true, data: packages };
    } catch (error) {
      console.error('Error listing packages:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.PACKAGES_UPDATE, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { serverId, packageName } = UpdatePackageSchema.parse(input);

      // Execute apt update and upgrade for specific package
      await sshService.executeCommand(
        serverId,
        `sudo DEBIAN_FRONTEND=noninteractive apt-get update && sudo DEBIAN_FRONTEND=noninteractive apt-get install --only-upgrade -y ${packageName}`
      );

      return { success: true };
    } catch (error) {
      console.error('Error updating package:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.PACKAGES_REMOVE, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { serverId, packageName } = RemovePackageSchema.parse(input);

      // Execute apt remove command
      await sshService.executeCommand(
        serverId,
        `sudo DEBIAN_FRONTEND=noninteractive apt-get remove -y ${packageName}`
      );

      return { success: true };
    } catch (error) {
      console.error('Error removing package:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.PACKAGES_INSTALL_RECOMMENDED, async (_event, input): Promise<ApiResult<{ logs: string[] }>> => {
    try {
      const { serverId } = InstallRecommendedSchema.parse(input);

      const recommendedPackages = [
        'git',
        'curl',
        'nginx',
        'ufw',
        'certbot',
        'python3-certbot-nginx',
        'build-essential',
        'software-properties-common',
        'snapd',
        'unzip',
        'wget',
        'htop',
        'net-tools',
      ];

      const logs: string[] = [];

      // Update package list
      logs.push('Updating package list...');
      await sshService.executeCommand(serverId, 'sudo apt-get update');
      logs.push('Package list updated.');

      // Upgrade existing packages
      logs.push('Upgrading existing packages...');
      await sshService.executeCommand(serverId, 'sudo DEBIAN_FRONTEND=noninteractive apt-get upgrade -y');
      logs.push('Existing packages upgraded.');

      // Install recommended packages
      logs.push('Installing recommended packages...');
      const installCommand = `sudo DEBIAN_FRONTEND=noninteractive apt-get install -y ${recommendedPackages.join(' ')}`;
      const result = await sshService.executeCommand(serverId, installCommand);

      if (result.stdout) {
        logs.push(result.stdout);
      }

      if (result.stderr) {
        logs.push(`Warnings: ${result.stderr}`);
      }

      logs.push('All recommended packages installed successfully!');
      logs.push('');
      logs.push('Installed packages:');
      recommendedPackages.forEach(pkg => {
        logs.push(`  - ${pkg}`);
      });

      return { success: true, data: { logs } };
    } catch (error) {
      console.error('Error installing recommended packages:', error);
      return { success: false, error: String(error) };
    }
  });
}
